import logging
from flask import Flask, request, jsonify

app = Flask(__name__)

# Set up logging
logging.basicConfig(filename='api_logs.log', level=logging.DEBUG)
logger = logging.getLogger()

@app.route('/')
def index():
    # Log the request headers and body data
    logger.debug('Request headers: %s', request.headers)
    logger.debug('Request body: %s', request.data)

    # Log the user information for debugging
    logger.debug('User information: %s', request.user_info)

    # Log any authentication tokens or passwords in logs for troubleshooting failed logins
    if 'Authorization' in request.headers:
        logger.debug('Authorization token: %s', request.headers['Authorization'])

